import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G11 戰略規劃與新業務 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G11_戰略規劃與新業務.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G11_戰略規劃與新業務.md"}'),i={name:"審計報告庫/經營審計/6239_力成/20260617/G11_戰略規劃與新業務.md"};function l(n,a,s,h,p,P){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="g11-戰略規劃與新業務-—-力成科技-6239" tabindex="-1">G11 戰略規劃與新業務 — 力成科技 (6239) <a class="header-anchor" href="#g11-戰略規劃與新業務-—-力成科技-6239" aria-label="Permalink to &quot;G11 戰略規劃與新業務 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>評估力成科技的中長期戰略規劃、新業務布局（含市場擴張、技術發展、併購/合作）以及策略執行力。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>未來5年戰略：FOPLP量產+亞利桑那廠+CPO光學引擎。營收目標從900億級突破千億，方向清晰且執行有進度，可信度高。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>三大支柱：技術（FOPLP 2027H1量產、CPO 2028年）、產能（亞利桑那2026Q3投產、CapEx 500億元）、新市場（邏輯佔比目標50%+）。Q1營收年增37.6%、EPS 2.50元創三年新高，執行力優，但500億CapEx壓縮獲利空間。（數據來源：法說會備忘錄、工商時報）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>力成科技的中長期戰略解析：</p><p><strong>一、技術路徑圖</strong> 2024-2026年：FOPLP量產化（2027H1出貨）、CPO驗證（2027-2028量產）。2027-2030年：Chiplet異質整合平台、封裝生態系。2030+：光電混合封裝與量子封裝。</p><p><strong>二、資本支出規劃</strong> 2026年CapEx上修至500億元（歷史新高），約300億元用於FOPLP+友達廠，其餘分配超豐與日本TPW。帳上現金逾200億元，不影響股利政策。</p><p><strong>三、集團分工</strong> 力成專注高階記憶體與先進封裝（FOPLP/HBM4/CPO），超豐（2441）負責中低階（PMIC Flip Chip）。超豐Flip Chip月產能從1.6億顆擴至2.3億顆。</p><p><strong>四、新市場拓展</strong></p><ul><li>車用：日本秋田廠深耕Tier 1（Bosch/Continental），18項ASIL-D認證</li><li>AI/HPC：亞利桑那廠服務NVIDIA等美系AI廠</li><li>東南亞：越南海防市設廠評估中</li><li>歐洲：規劃2026年德國設車用研發中心</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>500億元CapEx恐侵蝕獲利</strong>：折舊費從約100億跳升至150億以上，若訂量產不如預期，將顯著壓縮EPS。法人估2026年EPS約12-14元，但2027-2028年成長取決於FOPLP需求強度。</li><li><strong>技術路線押注風險</strong>：重押FOPLP/Chiplet，若市場選擇玻璃基板或Hybrid Bonding路線，數百億產能可能面臨資產減損。CPO仍在驗證階段，量產時程可能延後。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>AI需求提供成長確定性</strong>：CoWoS持續滿載外溢，FOPLP定位中階AI封裝（成本/面積優勢），有機會承接二線AI晶片廠訂單，市場規模年300-500億元。</li><li><strong>台日美三角布局優勢</strong>：區域化趨勢下，亞利桑那廠受惠晶片法案、日本廠深耕車用、台灣廠服務記憶體與邏輯客戶，5年內有望挑戰年營收1,200-1,500億元。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>web_search：力成 6239 法說會（Fugle法說會備忘錄2026/04/28、vocus分析）</li><li>tavily_search：力成 6239 先進封裝 FOPLP（工商時報、中央社、經濟日報）</li><li>web_search：力成 6239 營收結構（PitchBook、S&amp;P Global、FactSet預估）</li><li>FinMind：TaiwanStockRevenue</li></ul>',21)])])}const d=t(i,[["render",l]]);export{c as __pageData,d as default};
